import{_ as a,o,c as l,a3 as e}from"./chunks/framework.BTFg6ESq.js";const d=JSON.parse('{"title":"续写与智能补全","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/messages/continue-completion.md","filePath":"user-guide/tools/llm-chat/messages/continue-completion.md","lastUpdated":1778239080000}'),i={name:"user-guide/tools/llm-chat/messages/continue-completion.md"};function n(r,t,s,h,u,c){return o(),l("div",null,[...t[0]||(t[0]=[e('<h1 id="续写与智能补全" tabindex="-1">续写与智能补全 <a class="header-anchor" href="#续写与智能补全" aria-label="Permalink to &quot;续写与智能补全&quot;">​</a></h1><p>LLM Chat 提供了强大的内容延续功能，利用 AI 的预测能力协助你突破创作瓶颈。这些功能涵盖了从助手回复的延续到输入框内的实时灵感接力。</p><h2 id="_1-助手续写-assistant-continue" tabindex="-1">1. 助手续写 (Assistant Continue) <a class="header-anchor" href="#_1-助手续写-assistant-continue" aria-label="Permalink to &quot;1. 助手续写 (Assistant Continue)&quot;">​</a></h2><p>当模型的回复因为 Token 限制被截断，或者你希望模型在当前思路的基础上进一步深入时，可以使用“续写”功能。</p><h3 id="核心机制" tabindex="-1">核心机制 <a class="header-anchor" href="#核心机制" aria-label="Permalink to &quot;核心机制&quot;">​</a></h3><ul><li><strong>非破坏性生成</strong>：续写不会覆盖原始消息，而是会创建一个新的分支节点。</li><li><strong>上下文继承</strong>：系统会自动将当前消息的内容作为“前缀”（Prefix/Prefill）发送给模型，确保生成的内容与现有文本严丝合缝。</li><li><strong>状态感知</strong>：如果模型支持原生“前缀补全”特性（如 DeepSeek、Claude），续写将极其精准；对于其他模型，系统会通过 Prompt 指引实现类似效果。</li></ul><h3 id="操作方式" tabindex="-1">操作方式 <a class="header-anchor" href="#操作方式" aria-label="Permalink to &quot;操作方式&quot;">​</a></h3><ol><li>在任意一条助手消息上，点击右键或点击消息工具栏的 <strong>更多 (Menu)</strong> 按钮。</li><li>选择 <strong>续写消息 (Continue)</strong>。</li><li><strong>指定模型续写</strong>：如果你发现当前模型续写效果不佳，可以选择“选择模型续写”，临时调用能力更强的模型（如 Claude 3.5 Sonnet）来接力完成长文本。</li></ol><h2 id="_2-输入补全-input-copilot" tabindex="-1">2. 输入补全 (Input Copilot) <a class="header-anchor" href="#_2-输入补全-input-copilot" aria-label="Permalink to &quot;2. 输入补全 (Input Copilot)&quot;">​</a></h2><p>输入补全功能将 AI 引入你的写作过程，在输入框内提供实时的文思辅助。</p><h3 id="功能特性" tabindex="-1">功能特性 <a class="header-anchor" href="#功能特性" aria-label="Permalink to &quot;功能特性&quot;">​</a></h3><ul><li><strong>上下文感知</strong>：补全请求不仅包含输入框已有的文字，还会参考当前对话的上下文，确保补全建议符合逻辑。</li><li><strong>流式回填</strong>：补全内容会以流式方式直接追加到输入框中，你可以随时观察生成过程。</li><li><strong>轻量级请求</strong>：补全使用独立的临时请求，不占用对话历史，不产生冗余的消息节点。</li></ul><h3 id="使用方法" tabindex="-1">使用方法 <a class="header-anchor" href="#使用方法" aria-label="Permalink to &quot;使用方法&quot;">​</a></h3><ol><li>在输入框工具栏中点击 <strong>更多 (MoreHorizontal)</strong> 按钮。</li><li>选择 <strong>智能补全 (Sparkles)</strong>。</li><li>AI 将根据你当前输入的文字生成后续内容并自动填入。</li></ol><div class="tip custom-block github-alert"><p class="custom-block-title">提示</p><p>你可以在“更多”菜单中选择 <strong>指定补全模型</strong>。建议使用响应速度快、指令遵循能力强的模型（如 GPT-4o-mini）作为补全助手，以获得最佳的“随写随出”体验。</p></div><h2 id="_3-灵感接力-inspiration-relay" tabindex="-1">3. 灵感接力 (Inspiration Relay) <a class="header-anchor" href="#_3-灵感接力-inspiration-relay" aria-label="Permalink to &quot;3. 灵感接力 (Inspiration Relay)&quot;">​</a></h2><p>灵感接力是一种特殊的续写模式，允许 AI 站在“用户”的视角继续书写消息。</p><h3 id="场景应用" tabindex="-1">场景应用 <a class="header-anchor" href="#场景应用" aria-label="Permalink to &quot;场景应用&quot;">​</a></h3><ul><li><strong>角色换位</strong>：在进行角色扮演（RP）或创意写作时，如果你不知道下一步该如何行动，可以让 AI 帮你构思一段用户的后续动作或对白。</li><li><strong>长文拆分</strong>：当你有一段复杂的指令需要分步完善时，可以先写个开头，由 AI 接力完成细节描述。</li></ul><h3 id="触发方式" tabindex="-1">触发方式 <a class="header-anchor" href="#触发方式" aria-label="Permalink to &quot;触发方式&quot;">​</a></h3><ul><li>在任意一条 <strong>用户消息</strong> 上，点击工具栏的 <strong>更多</strong> -&gt; <strong>续写消息</strong>。</li><li>系统会识别出当前是用户节点，并引导 AI 延续该节点的语气和内容进行扩写。</li></ul><h2 id="_4-交互细节说明" tabindex="-1">4. 交互细节说明 <a class="header-anchor" href="#_4-交互细节说明" aria-label="Permalink to &quot;4. 交互细节说明&quot;">​</a></h2><ul><li><strong>终止生成</strong>：续写和补全过程中，你可以随时点击工具栏上的 <strong>停止 (Abort)</strong> 按钮中断生成。</li><li><strong>Token 统计</strong>：续写生成的 Token 消耗会独立记录在该消息节点的元数据中。</li><li><strong>历史记录</strong>：续写产生的每一个版本都会作为对话树的一个分支被保留，你可以通过消息顶部的分支切换器在不同版本的续写结果间跳转。</li></ul><hr><p><strong>相关阅读</strong>：</p><ul><li><a href="./../sessions/tree-graph">对话分支管理</a></li><li><a href="./../tool-calling/">工具调用执行</a></li><li><a href="./../context-pipeline/analyzer">上下文分析器</a></li></ul>',26)])])}const p=a(i,[["render",n]]);export{d as __pageData,p as default};
